+
+/**
+ * Sanitizes a string for safe use as an HTML attribute value.
+ * Escapes characters that could break out of attribute context.
+ */
+export const sanitizeHTMLAttribute = (value: string): string => {
+  return value
+    .replace(/&/g, "&amp;")
+    .replace(/"/g, "&quot;")
+    .replace(/'/g, "&#x27;")
+    .replace(/</g, "&lt;")
+    .replace(/>/g, "&gt;")
+    .replace(/\//g, "&#x2F;")
+    .replace(/\\/g, "&#x5C;")
+    .replace(/`/g, "&#96;");
+};
+
+/**
+ * Sanitizes HTML content for use in srcdoc by strictly parsing
+ * and reconstructing safe HTML, rather than rendering untrusted
+ * content verbatim.
+ */
+export const sanitizeHTMLContent = (html: string): string => {
+  // Strip any script tags and event handlers
+  let sanitized = html;
+  
+  // Remove script tags and their content
+  sanitized = sanitized.replace(
+    /<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi,
+    "",
+  );
+  
+  // Remove event handler attributes (on*)
+  sanitized = sanitized.replace(
+    /\s+on\w+\s*=\s*(?:"[^"]*"|'[^']*'|[^\s>]+)/gi,
+    "",
+  );
+  
+  // Remove javascript: URLs
+  sanitized = sanitized.replace(
+    /(?:href|src|action)\s*=\s*(?:"javascript:[^"]*"|'javascript:[^']*')/gi,
+    "",
+  );
+  
+  // Remove data: URLs that could contain scripts
+  sanitized = sanitized.replace(
+    /(?:href|src|action)\s*=\s*(?:"data:text\/html[^"]*"|'data:text\/html[^']*')/gi,
+    "",
+  );
+  
+  return sanitized;
+};

