+/**
+ * Sanitize an SVG string to prevent XSS attacks.
+ * Removes script elements, event handler attributes, and other dangerous content.
+ * @param {string} svgString - The SVG string to sanitize.
+ * @returns {string} The sanitized SVG string.
+ */
+const sanitizeSvg = function (svgString) {
+    if (!svgString) return svgString;
+
+    const parser = new DOMParser();
+    const doc = parser.parseFromString(svgString, 'image/svg+xml');
+
+    // Remove all script elements
+    const scripts = doc.querySelectorAll('script');
+    for (const script of scripts) {
+        script.parentNode.removeChild(script);
+    }
+
+    // Remove foreignObject elements which can contain arbitrary HTML
+    const foreignObjects = doc.querySelectorAll('foreignObject');
+    for (const fo of foreignObjects) {
+        fo.parentNode.removeChild(fo);
+    }
+
+    // Remove all event handler attributes from all elements
+    const allElements = doc.querySelectorAll('*');
+    for (const element of allElements) {
+        const attributes = Array.from(element.attributes);
+        for (const attr of attributes) {
+            const attrName = attr.name.toLowerCase();
+            // Remove event handler attributes (on*)
+            if (attrName.startsWith('on')) {
+                element.removeAttribute(attr.name);
+            }
+            // Remove javascript: URLs in href/xlink:href attributes
+            if ((attrName === 'href' || attrName === 'xlink:href') &&
+                attr.value.replace(/\s/g, '').toLowerCase().startsWith('javascript:')) {
+                element.removeAttribute(attr.name);
+            }
+            // Remove data: URLs in href attributes that could contain scripts
+            if ((attrName === 'href' || attrName === 'xlink:href') &&
+                attr.value.replace(/\s/g, '').toLowerCase().startsWith('data:text/html')) {
+                element.removeAttribute(attr.name);
+            }
+        }
+    }
+
+    const serializer = new XMLSerializer();
+    return serializer.serializeToString(doc.documentElement);
+};
+
+module.exports = sanitizeSvg;

