+    // Parse the QE Identity issuer chain
+    let issuer_chain_pem = &collateral.qe_identity_issuer_chain;
+    let certs = X509::stack_from_pem(issuer_chain_pem.as_bytes())
+        .map_err(|_| Error::InvalidCertificateChain)?;
